benchmarks/graph/v2/runs/codex/graph-only/trace-policy-denial-wiring/1.transcript.json:41:{"type":"item.completed","item":{"id":"item_22","type":"command_execution","command":"/bin/zsh -lc \"orbit tool run orbit.graph.show --input '{\\\"selector\\\":\\\"symbol:crates/orbit-engine/src/activity_job/tool_enforcement.rs#EnforcedAuditSink::emit:method\\\"}'\"","aggregated_output":"{\"children\":[],\"lineage\":[\"dir:crates/orbit-engine/src/activity_job\",\"file:crates/orbit-engine/src/activity_job/tool_enforcement.rs\"],\"lines\":[56,108],\"selector\":\"symbol:crates/orbit-engine/src/activity_job/tool_enforcement.rs#EnforcedAuditSink::emit:method\",\"siblings\":[\"symbol:crates/orbit-engine/src/activity_job/tool_enforcement.rs#EnforcementDecision:struct\",\"symbol:crates/orbit-engine/src/activity_job/tool_enforcement.rs#EnforcedAuditSink:struct\",\"symbol:crates/orbit-engine/src/activity_job/tool_enforcement.rs#EnforcedAuditSink::new:method\"],\"source\":\"fn emit(&self, event: &LoopAuditEvent) {\\n        // Two paths can trigger the denial:\\n        //\\n        // 1. `AgentLoop` enforces the allowlist internally BEFORE dispatching\\n        //    a `ToolCallRequested` event and emits its own `PolicyDenial`.\\n        //    When we see a `PolicyDenial`, we mirror it into a §7\\n        //    `tool.denied` envelope event so the higher-level trail records\\n        //    the policy outcome alongside the loop-level event.\\n        //\\n        // 2. A caller that bypasses the loop's own check could still emit a\\n        //    `ToolCallRequested` for a tool we shouldn't allow — we catch\\n        //    that here too and synthesize both a §7 `tool.denied` envelope\\n        //    event and a loop-level `PolicyDenial`.\\n        match event {\\n            LoopAuditEvent::PolicyDenial {\\n                tool_name, reason, ..\\n            } => {\\n                let _ = self.writer.emit(V2AuditEventKind::ToolDenied {\\n                    tool_name: tool_name.clone(),\\n                    reason: reason.clone(),\\n                });\\n                *self.tripped.lock().expect(\\\"tripped mutex\\\") = Some(EnforcementDecision::Denied {\\n                    tool_name: tool_name.clone(),\\n                    reason: reason.clone(),\\n                });\\n                self.inner.emit(event);\\n            }\\n            LoopAuditEvent::ToolCallRequested { tool_name, .. }\\n                if !tool_allowed(tool_name, &self.allowlist) =>\\n            {\\n                let reason = format!(\\\"tool `{tool_name}` not in allowlist\\\");\\n                let _ = self.writer.emit(V2AuditEventKind::ToolDenied {\\n                    tool_name: tool_name.clone(),\\n                    reason: reason.clone(),\\n                });\\n                self.inner.emit(event);\\n                let denial = LoopAuditEvent::PolicyDenial {\\n                    ts: chrono::Utc::now(),\\n                    run_id: self.run_id.clone(),\\n                    session_id: self.session_id.clone(),\\n                    iteration: 0,\\n                    tool_name: tool_name.clone(),\\n                    reason: reason.clone(),\\n                };\\n                self.inner.emit(&denial);\\n                *self.tripped.lock().expect(\\\"tripped mutex\\\") = Some(EnforcementDecision::Denied {\\n                    tool_name: tool_name.clone(),\\n                    reason,\\n                });\\n            }\\n            _ => self.inner.emit(event),\\n        }\\n    }\"}\n","exit_code":0,"status":"completed"}}
